import azure.functions as func
from azure.storage.blob import BlobServiceClient, generate_blob_sas, BlobSasPermissions
from datetime import datetime, timedelta

def main(req: func.HttpRequest) -> func.HttpResponse:
    # Validate input
    blob_path = req.params.get('path')
    if not blob_path:
        return func.HttpResponse("Please provide a valid blob path.", status_code=400)

    try:
        # Replace with your Azure Storage connection string
        connection_string = "your_connection_string_here"
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        
        # Split the path into container and blob name
        container_name, blob_name = blob_path.split('/', 1)
        
        # Get the blob client
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        
        # Generate a SAS token for secure access to the blob
        sas_token = generate_blob_sas(account_name="your_account_name",
                                      account_key="your_account_key",
                                      container_name=container_name,
                                      blob_name=blob_name,
                                      permission=BlobSasPermissions(read=True),
                                      expiry=datetime.utcnow() + timedelta(hours=1))
        
        # Construct the SAS URL
        sas_url = f"{blob_client.url}?{sas_token}"
        
        return func.HttpResponse(f"SAS URL: {sas_url}", status_code=200)
    
    except Exception as e:
        return func.HttpResponse(str(e), status_code=500)